@import "tailwindcss";

:root {
  --background: #0a0a0a;
  --background-card: #111111;
  --background-elevated: #1a1a1a;
  --foreground: #fafafa;
  --foreground-muted: #a1a1aa;
  --foreground-subtle: #71717a;
  --accent: #10b981;
  --accent-blue: #3b82f6;
  --border: #27272a;
  --border-hover: #3f3f46;
}

@theme inline {
  --color-background: var(--background);
  --color-background-card: var(--background-card);
  --color-background-elevated: var(--background-elevated);
  --color-foreground: var(--foreground);
  --color-foreground-muted: var(--foreground-muted);
  --color-foreground-subtle: var(--foreground-subtle);
  --color-accent: var(--accent);
  --color-accent-blue: var(--accent-blue);
  --color-border: var(--border);
  --color-border-hover: var(--border-hover);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
}

html {
  scroll-behavior: smooth;
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-sans), system-ui, sans-serif;
}

/* Fluid typography scale */
h1 {
  font-size: clamp(2.25rem, 5vw, 3.75rem);
  line-height: 1.1;
  font-weight: 700;
  letter-spacing: -0.02em;
}

h2 {
  font-size: clamp(1.75rem, 3.5vw, 2.5rem);
  line-height: 1.2;
  font-weight: 600;
  letter-spacing: -0.01em;
}

h3 {
  font-size: clamp(1.25rem, 2.5vw, 1.75rem);
  line-height: 1.3;
  font-weight: 600;
}

h4 {
  font-size: clamp(1.1rem, 2vw, 1.25rem);
  line-height: 1.4;
  font-weight: 500;
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: var(--background);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--foreground-subtle);
}

/* Selection */
::selection {
  background: var(--accent);
  color: var(--background);
}

/* Terminal animations */
@keyframes terminal-blink {
  0%, 50% { opacity: 1; }
  51%, 100% { opacity: 0; }
}

@keyframes terminal-dot-bounce {
  0%, 80%, 100% { transform: translateY(0); }
  40% { transform: translateY(-4px); }
}

@keyframes cam-code-breathe {
  0%, 100% { box-shadow: 0 0 20px rgba(16, 185, 129, 0.3); }
  50% { box-shadow: 0 0 35px rgba(16, 185, 129, 0.55); }
}

@keyframes scroll-left {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

