  6→import { ScrollReveal } from "@/components/interactive/ScrollReveal";
  7→import type { Project } from "@/data/projects";
  8→
  9→interface ProjectListProps {
 10→  projects: Project[];
 11→}
 12→
 13→const MONTHS: Record<string, number> = {
 14→  january: 1, february: 2, march: 3, april: 4, may: 5, june: 6,
 15→  july: 7, august: 8, september: 9, october: 10, november: 11, december: 12,
 16→};
 17→
 18→function parseDateValue(s: string): number {
 19→  const t = s.trim().toLowerCase();
 20→  if (t === "present") return Infinity;
 21→  for (const [month, num] of Object.entries(MONTHS)) {
 22→    if (t.startsWith(month)) {
 23→      const year = parseInt(t.match(/\d{4}/)?.[0] || "0");
 24→      return year * 100 + num;
 25→    }
 26→  }
 27→  const year = parseInt(t);
 28→  return !isNaN(year) ? year * 100 + 12 : 0;
 29→}
 30→
 31→function getDateBounds(dateStr: string) {
 32→  const parts = dateStr.split(/\s*[–\-]\s*/);
 33→  const start = parseDateValue(parts[0]);
 34→  const end = parts.length > 1 ? parseDateValue(parts[parts.length - 1]) : start;
 35→  return { start, end };
 36→}
 37→
 38→function sortByDate(list: Project[]): Project[] {
 39→  return [...list].sort((a, b) => {
 40→    const aD = getDateBounds(a.date);
 41→    const bD = getDateBounds(b.date);
 42→    if (bD.end !== aD.end) return bD.end - aD.end;
 43→    return bD.start - aD.start;
 44→  });
 45→}
 46→
 47→export function ProjectList({ projects }: ProjectListProps) {
 48→  const [query, setQuery] = useState("");
 49→
 50→  const filtered = useMemo(() => {
 51→    const base = query.trim()
 52→      ? projects.filter((p) => {
 53→          const q = query.toLowerCase();
 54→          return (
 55→            p.title.toLowerCase().includes(q) ||
 56→            p.description.toLowerCase().includes(q) ||
 57→            p.techStack.some((t) => t.toLowerCase().includes(q)) ||
 58→            p.category.toLowerCase().includes(q)
 59→          );
 60→        })
 61→      : projects;
 62→    return sortByDate(base);
 63→  }, [projects, query]);
 64→
 65→  const featured = filtered.filter((p) => p.featured);
 66→  const archive = filtered.filter((p) => !p.featured);
 67→
 68→  return (
